// ============================================
// FUNÇÃO PARA PEGAR ESTADO DO USUÁRIO
// ============================================
const redis = require('redis');
const client = redis.createClient({
  socket: {
    host: 'redis',
    port: 6379
  }
});

await client.connect();

const userId = $json.chatId?.replace('@s.whatsapp.net', '');
const stateKey = `flow:${userId}`;

const stateData = await client.get(stateKey);
const userState = stateData ? JSON.parse(stateData) : null;

await client.quit();

return {
  userId: userId,
  userState: userState,
  messageText: $json.messageText,
  senderName: $json.pushName || 'Usuário'
};

// ============================================
// SALVA ESTADO INICIAL
// ============================================
const redis = require('redis');
const client = redis.createClient({
  socket: {
    host: 'redis',
    port: 6379
  }
});

await client.connect();

const userId = $json.userId;
const stateKey = `flow:${userId}`;

const stateValue = JSON.stringify({
  state: 'aguardando_placa',
  data: {},
  updatedAt: new Date().toISOString()
});

await client.setEx(stateKey, 900, stateValue);
await client.quit();

return { success: true };

const stats = $json[0];
let mensagem = '📊 *STATUS DO SISTEMA*\n\n';
mensagem += `📦 Total de abastecimentos: *${stats.total}*\n`;
mensagem += `👥 Usuários únicos: *${stats.usuarios_unicos}*\n`;
mensagem += `🚗 Placas únicas: *${stats.placas_unicas}*\n`;
mensagem += `⛽ Total de litros: *${stats.total_litros}L*\n`;
mensagem += `📈 Média por abastecimento: *${Math.round(stats.media_litros)}L*\n`;
mensagem += `📅 Últimas 24h: *${stats.ultimas_24h}*\n`;

return { text: mensagem };

const abastecimentos = $json;
if (abastecimentos.length === 0) {
  return { text: '📭 Nenhum abastecimento registrado ainda.' };
}

let mensagem = '📋 *SEUS ÚLTIMOS ABASTECIMENTOS*\n\n';
abastecimentos.forEach((a, index) => {
  const data = new Date(a.criado_em).toLocaleDateString('pt-BR');
  mensagem += `${index + 1}. 🚗 *${a.placa}* | ${a.km} km | ${a.litros}L\n`;
  mensagem += `   📅 ${data}\n`;
});

return { text: mensagem };

// ============================================
// PROCESSADOR DE ESTADOS
// ============================================
const userState = $json.userState;
const userId = $json.userId;
const messageText = $json.messageText;
const senderName = $json.senderName;

// ============================================
// FUNÇÃO DE VALIDAÇÃO
// ============================================
function isValidPlaca(placa) {
  const mercosul = /^[A-Z]{3}[0-9][A-Z][0-9]{2}$/;
  const antigo = /^[A-Z]{3}[0-9]{4}$/;
  return mercosul.test(placa) || antigo.test(placa);
}

function isValidKm(km) {
  return !isNaN(km) && parseInt(km) > 0;
}

function isValidLitros(litros) {
  return !isNaN(litros) && parseFloat(litros) > 0 && parseFloat(litros) < 10000;
}

const redis = require('redis');
const client = redis.createClient({
  socket: {
    host: 'redis',
    port: 6379
  }
});

await client.connect();

const stateKey = `flow:${userId}`;
let response = null;
let newState = null;
const flowData = userState.data || {};

switch (userState.state) {
  // ============================================
  // PASSO 1: PLACA
  // ============================================
  case 'aguardando_placa':
    if (!messageText) {
      response = '⚠️ Por favor, informe a *PLACA* do veículo (ex: ABC1D23 ou ABC1234):';
      break;
    }

    const placa = messageText.toUpperCase().trim();
    if (!isValidPlaca(placa)) {
      response = '❌ *Placa inválida!*\n\nUse o formato:\n• Mercosul: ABC1D23\n• Antigo: ABC1234\n\nDigite novamente:';
      break;
    }

    newState = { state: 'aguardando_km', data: { placa } };
    response = `✅ Placa *${placa}* registrada!\n\n2️⃣ Agora informe a *KM ATUAL* do veículo:`;
    break;

  // ============================================
  // PASSO 2: KM
  // ============================================
  case 'aguardando_km':
    if (!messageText) {
      response = '⚠️ Por favor, informe a *KM* atual do veículo (apenas números):';
      break;
    }

    const km = parseInt(messageText.trim());
    if (!isValidKm(km)) {
      response = '❌ *KM inválida!*\n\nDigite apenas números (ex: 15234)\n\nInforme a KM novamente:';
      break;
    }

    newState = { state: 'aguardando_litros', data: { ...flowData, km } };
    response = `✅ KM *${km}* registrada!\n\n3️⃣ Agora informe a *QUANTIDADE DE LITROS* abastecidos:`;
    break;

  // ============================================
  // PASSO 3: LITROS
  // ============================================
  case 'aguardando_litros':
    if (!messageText) {
      response = '⚠️ Por favor, informe a *QUANTIDADE DE LITROS* (ex: 45.5):';
      break;
    }

    const litros = parseFloat(messageText.trim().replace(',', '.'));
    if (!isValidLitros(litros)) {
      response = '❌ *Quantidade inválida!*\n\nDigite um número válido (ex: 45.5)\n\nInforme os litros novamente:';
      break;
    }

    newState = { state: 'aguardando_foto_odometro', data: { ...flowData, litros } };
    response = `✅ *${litros} litros* registrados!\n\n4️⃣ Agora envie a *FOTO DO ODÔMETRO*:\n(Clique no 📎 e selecione a imagem)`;
    break;

  // ============================================
  // PASSO 4: FOTO ODÔMETRO
  // ============================================
  case 'aguardando_foto_odometro':
    // Verificar se recebeu imagem
    if (!$json.media) {
      response = '⚠️ Por favor, envie a *FOTO DO ODÔMETRO*.\n\nClique no 📎 e selecione a imagem:';
      break;
    }

    // Salvar foto (precisa de um node de download de mídia)
    const fotoOdometro = `odometro_${userId}_${Date.now()}.jpg`;
    newState = { state: 'aguardando_foto_abastecimento', data: { ...flowData, foto_odometro: fotoOdometro } };
    response = '✅ Foto do odômetro registrada!\n\n5️⃣ Agora envie a *FOTO DO ABASTECIMENTO* (bomba/nota):';
    break;

  // ============================================
  // PASSO 5: FOTO ABASTECIMENTO
  // ============================================
  case 'aguardando_foto_abastecimento':
    // Verificar se recebeu imagem
    if (!$json.media) {
      response = '⚠️ Por favor, envie a *FOTO DO ABASTECIMENTO*.\n\nClique no 📎 e selecione a imagem:';
      break;
    }

    // Salvar foto
    const fotoAbastecimento = `abastecimento_${userId}_${Date.now()}.jpg`;

    // Salvar no PostgreSQL (via função)
    const pg = require('pg');
    const pool = new pg.Pool({
      host: 'postgres',
      port: 5432,
      database: 'abastecimento',
      user: 'admin',
      password: 'admin123'
    });

    await pool.query(
      'SELECT registrar_abastecimento($1, $2, $3, $4, $5, $6, $7) as id',
      [
        userId,
        senderName,
        flowData.placa,
        flowData.km,
        flowData.litros,
        flowData.foto_odometro || null,
        fotoAbastecimento
      ]
    );

    await pool.end();

    // Limpa estado
    await client.del(stateKey);

    response = `✅ *ABASTECIMENTO REGISTRADO COM SUCESSO!*\n\n` +
               `📋 *Dados:*\n` +
               `🚗 Placa: *${flowData.placa}*\n` +
               `📏 KM: *${flowData.km}*\n` +
               `⛽ Litros: *${flowData.litros}L*\n` +
               `📸 Fotos: 2 imagens salvas\n` +
               `🕐 Data: *${new Date().toLocaleDateString('pt-BR')}*\n\n` +
               `Obrigado! Para novo abastecimento, digite */abast*`;

    // Resposta final (não salva novo estado)
    break;

  default:
    await client.del(stateKey);
    response = '⚠️ Fluxo reiniciado. Digite */abast* para começar.';
}

// Atualiza estado se necessário
if (newState) {
  const stateValue = JSON.stringify({
    state: newState.state,
    data: newState.data,
    updatedAt: new Date().toISOString()
  });
  await client.setEx(stateKey, 900, stateValue);
}

await client.quit();

return {
  userId: userId,
  response: response,
  shouldSaveState: !!newState
};
